<span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">unshare</span><span style="--shiki-light:#A65E2B;--shiki-dark:#C99076;"> --mount</span><span style="--shiki-light:#A65E2B;--shiki-dark:#C99076;"> --fork</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> /bin/bash</span></span>
