<span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">ipcs</span><span style="--shiki-light:#A65E2B;--shiki-dark:#C99076;"> -m</span><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;">         # 查看共享内存段</span></span>
